int countPalindromeSubstrings(string s)  
{  
    // To store the length of palindromic substrings 
    int count = 0;  

    // Iterate over all possible centres  
    for(int i = 0; i < s.length(); ++i)  
    {  
        // Expand from possible centres 
        for(int j = 0; i - j >= 0 && i + j < s.length(); ++j) 
        {  
            // Check if the current substrings is a palindrome 
            if(s[i - j] == s[i + j]) 
            {  
                count++; 
            } 
            else
            {
                break; 
            }
        }  

        // Expand from possible centres 
        for (int j = 1; i - j + 1 >= 0 && i + j < s.length(); ++j) 
        { 
            // Check if the current substrings is a palindrome 
            if (s[i - j + 1] == s[i + j]) 
            {  
                count++; 
            } 
            else 
            { 
                break; 
            }  
        }  
    }  

    return count;  
}

