TreeNode* LCA(TreeNode* root,TreeNode* node1, TreeNode* node2) 
{ 
    int small = min(node1->data, node2->data);
    int large = max(node1->data, node2->data);

    if (root == NULL) 
        return NULL; 

    if (root->data >= small && root->data <= large) 
