function findPerfectNumbers(n) {
  var perfects = [];

  for(var i = 1; i<=n; i++){
    var divisorsSum = 0;
    for(var j = 1; j<i; j++){
      if(i % j == 0){
        divisorsSum += j;
      }
    }
    if(divisorsSum == i){
      perfects.push(i);
    }
  }

  return perfects;
}

def is_palindrome(string):
    left, right = 0, len(string)-1

    while right >= left:
        if string[left] != string[right]:
            return False
        left += 1
        right -= 1
    return True

