     * @param target the element to search for
     * @return the index of the element if found, -1 otherwise
     */
    public static int linearSearch(int[] arr, int target) 
    { 
        for (int i = 0; i < arr.length; i++) 
        { 
            if (arr[i] == target) 
            { 
                return i; 
            } 
        } 
        return -1;
