// Function to reverse words*/ 
void reverseWords(char* s) 
{ 
    char* word_begin = s; 

    // Word boundary 
    char* temp = s; 

    // Reversing individual words as 
    // explained in the first step 
    while (*temp) { 
        temp++; 
        if (*temp == '\0') { 
            ReverseString(word_begin, temp - 1); 
        } 
        else if (*temp == ' ') { 
            ReverseString(word_begin, temp - 1); 
            word_begin = temp + 1; 
        } 
    } 

    // Reverse the entire string 
    ReverseString(s, temp - 1); 
} 

