Node *generateBFSBinaryTree(vector<int> input_nodes) {
    Node *root = new Node{input_nodes[0]};
    queue<Node *> que;
    que.push(root);
    for (int i = 1; i < input_nodes.size(); ++i) {
        Node *node = new Node{input_nodes[i]};
        Node *par = que.front();
        que.pop();
        if (!par->left) {
            par->left = node;
        }
        else {
            par->right = node;
        }
        que.push(node);
    }
    return root;
}

