def get_prime_numbers(start, end):
    """
    Function to return a list of all the prime numbers between start and end
    """
    prime_numbers = []
    for num in range(start, end + 1):
        if num > 1:
            is_prime = True
            for j in range(2, int(num/2) + 1):
                if num % j == 0:
                    is_prime = False
                    break
            if is_prime:
