#include <stdlib.h>

#define MAX_NUM_TEAMS 8

struct team { 
  int teamID; 
  char name[30]; 
};

struct bracket {
  struct team *teams;
  int numTeams;
  int winningTeam;
};

void createBracket(struct bracket *bracket, int numTeams) {
  bracket->teams = calloc(numTeams, sizeof(struct team));
  bracket->numTeams = numTeams; 
  int matchups[numTeams/2][2] = {0};

  // Generate a list of matchups
  int i, j;
  for (i = 0; i < numTeams/2; i++) {
    for (j = 0; j < 2; j++) {
      int randID = rand() % numTeams;
      int found = 0;
      int k;
      for (k = 0; k < i*2+j; k++) {
        if (randID == matchups[k/2][k%2]) {
          found = 1;
          break;
        }
      }
      if (!found) {
        matchups[i][j] = randID;
      }
      else {
        j--;
      }
    }
  }

  // Generate list of teams
  for (i = 0; i < numTeams; i++) {
    struct team t;
    t.teamID = i;
    // Randomly generate team name
    int n;
    for (n = 0; n < 30; n++) {
      t.name[n] = (rand() % 26) + 'a';
    }
    bracket->teams[i] = t;
  }

  // Initialize the bracket with teams
  for (i = 0; i < numTeams/2; i++) {
    bracket->teams[matchups[i][0]].opponent = matchups[i][1];
    bracket->teams[matchups[i][1]].opponent = matchups[i][0];
  } 
}

void evaluateBracket(struct bracket *bracket, int winningTeam) {
  bracket->winningTeam = winningTeam;

  int count = 0;
  int currTeam = winningTeam;
  int opponent;

  while (currTeam != 0) {
    opponent = bracket->teams[currTeam].opponent;
    bracket->teams[opponent].opponent = -1;
    currTeam = opponent;
    count++;
  }
  if (count >= bracket->numTeams/2) {
    printf("Winner: %s\n", bracket->teams[winningTeam].name);
  }
  else {
    printf("The team %s has been eliminated from the tournament\n", bracket->teams[winningTeam].name);
  }
}

