    for num in nums:
        if num in countDict:
            countDict[num] += 1
        else:
            countDict[num] = 1
    maxValue = 0
    maxKey = -1
    for key, value in countDict.items():
        if value > maxValue:
            maxValue = value
            maxKey = key
    return maxKey

