def prime_factorize(num):
    '''This function takes in a number and returns all the prime factors.'''
    primes = []
    i = 2
    while i * i <= num:
        while num % i == 0:
            primes.append(i)
            num //= i
        i += 1
    if num > 1:
        primes.append(num)
    return primes

