def is_valid_isbn_10(code):
    # check for the length
    if len(code) != 10:
        return False
    # check for leading "X" characters
    if code.startswith("X"):
        return False
    # check for digits
    if not code.isdigit():
        return False
    # calculate the check digit
    sum = 0
    for i in range(9): 
        sum += int(code[i]) * (10 - i)
    checksum = sum % 11
    # check for valid check digit
    if not (checksum==int(code[9]) or (checksum == 10 and code[9] == 'X')):
        return False
    # No errors found
    return True

