std::vector<int> find_missing_numbers(const std::vector<int>::iterator begin,
                                      const std::vector<int>::iterator end) {
  int n = end - begin;
  int total_sum = (n + 2)*(n + 1)/2;

  int missing_sum = 0;
  for (auto it = begin; it != end; ++it) {
    missing_sum += *it;
  }

  int difference = total_sum - missing_sum;
  int a = difference/2;
  int b = a + difference;

  return {a, b};
}

