"""
Construct a Linked List class
"""

class Node: 
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def add_node(self, data):
        temp = Node(data) 
        temp.next = self.head
        self.head = temp

    def print_list(self):
        current = self.head
        while current:
            print(current.data)
            current = current.next

if __name__ == '__main__':
    llist = LinkedList()
    llist.add_node(1)
    llist.add_node(3)
    llist.add_node(5)
    llist.add_node(7)
    llist.print_list() # prints 7 5 3 1

